/* SPDX-License-Identifier: GPL-2.0-only */

#include <console/console.h>
#include <delay.h>
#include <device/mmio.h>
#include <stddef.h>
#include <stdint.h>

#include "dcn10.h"

/* Raven/Picasso DCN segments, from Linux vega10_ip_offset.h. */
#define DCN10_SEG1_BASE	0x00c0
#define DCN10_SEG2_BASE	0x34c0
#define DCN10_REG1(reg)	((DCN10_SEG1_BASE + (reg)) * 4)
#define DCN10_REG(reg)	((DCN10_SEG2_BASE + (reg)) * 4)

#define D1VGA_CONTROL			0x000c
#define D2VGA_CONTROL			0x000e
#define VGA_TEST_CONTROL		0x0015
#define D3VGA_CONTROL			0x0038
#define D4VGA_CONTROL			0x0039

#define DOMAIN0_PG_CONFIG		0x008a
#define DOMAIN0_PG_STATUS		0x008b
#define DOMAIN1_PG_CONFIG		0x008c
#define DOMAIN1_PG_STATUS		0x008d

#define DCSURF_SURFACE_CONFIG		0x0559
#define DCSURF_TILING_CONFIG		0x055b
#define DCSURF_PRI_VIEWPORT_START	0x055c
#define DCSURF_PRI_VIEWPORT_DIMENSION	0x055d
#define DCHUBP_REQ_SIZE_CONFIG		0x0564
#define DCHUBP_CNTL			0x0566
#define HUBP_CLK_CNTL			0x0567
#define DCSURF_SURFACE_PITCH		0x057b
#define DCSURF_PRIMARY_ADDRESS		0x057d
#define DCSURF_PRIMARY_ADDRESS_HIGH	0x057e
#define DCSURF_SURFACE_CONTROL		0x058d
#define DCSURF_FLIP_CONTROL		0x058e
#define DCSURF_EARLIEST_INUSE		0x0597
#define DCSURF_EARLIEST_INUSE_HIGH	0x0598
#define DCN_EXPANSION_MODE		0x059b
#define DCN_TTU_QOS_WM			0x059c
#define DCN_GLOBAL_TTU_CNTL		0x059d
#define DCN_SURF0_TTU_CNTL0		0x059e
#define DCN_SURF0_TTU_CNTL1		0x059f
#define BLANK_OFFSET_0			0x05b6
#define BLANK_OFFSET_1			0x05b7
#define DST_DIMENSIONS			0x05b8
#define DST_AFTER_SCALER		0x05b9
#define PREFETCH_SETTINS		0x05ba
#define VBLANK_PARAMETERS_0		0x05bc
#define PER_LINE_DELIVERY_PRE		0x05c9
#define PER_LINE_DELIVERY		0x05ca
#define REF_FREQ_TO_PIX_FREQ		0x05cc
#define HUBPRET_CONTROL			0x05e0
#define VTG_CONTROL			0x0528

#define DPP_CONTROL			0x0c3d
#define CNVC_SURFACE_PIXEL_FORMAT	0x0c47
#define CNVC_FORMAT_CONTROL		0x0c48
#define DSCL_SCL_MODE			0x0c64
#define DSCL_CONTROL			0x0c66
#define DSCL_RECOUT_START		0x0c7a
#define DSCL_RECOUT_SIZE		0x0c7b
#define DSCL_MPC_SIZE			0x0c7c

#define MPCC_TOP_SEL			0x1630
#define MPCC_BOT_SEL			0x1631
#define MPCC_OPP_ID			0x1632
#define MPCC_CONTROL			0x1633
#define MPCC_UPDATE_LOCK_SEL		0x1635
#define MPC_OUT_MUX			0x172f
#define OPP_PIPE_CONTROL		0x188c
#define OPTC_DATA_SOURCE_SELECT		0x1acb
#define OPTC_INPUT_CLOCK_CONTROL	0x1acd
#define OTG_H_TOTAL			0x1b2a
#define OTG_H_BLANK_START_END		0x1b2b
#define OTG_H_SYNC_A			0x1b2c
#define OTG_H_SYNC_A_CNTL		0x1b2d
#define OTG_H_TIMING_CNTL		0x1b2e
#define OTG_V_TOTAL			0x1b2f
#define OTG_V_TOTAL_MIN			0x1b30
#define OTG_V_TOTAL_MAX			0x1b31
#define OTG_V_BLANK_START_END		0x1b36
#define OTG_V_SYNC_A			0x1b37
#define OTG_V_SYNC_A_CNTL		0x1b38
#define OTG_CONTROL			0x1b41
#define OTG_BLANK_CONTROL		0x1b42
#define OTG_INTERLACE_CONTROL		0x1b44
#define OTG_DOUBLE_BUFFER_CONTROL	0x1b5b
#define OTG_CLOCK_CONTROL		0x1b88
#define OTG_VSTARTUP_PARAM		0x1b89
#define OTG_VUPDATE_PARAM		0x1b8a
#define OTG_VREADY_PARAM		0x1b8b

#define HUBP_BLANK_EN			(1U << 0)
#define HUBP_DISABLE			(1U << 2)
#define HUBP_VTG_SEL_MASK		(0xfU << 4)
#define HUBP_TTU_DISABLE		(1U << 12)
#define HUBP_CLOCK_ENABLE		(1U << 0)
#define DPP_CLOCK_ENABLE		(1U << 4)
#define OPP_PIPE_CLOCK_ENABLE		(1U << 0)

static uint32_t dcn10_read(void *mmio, uint32_t reg)
{
	return read32((uint8_t *)mmio + DCN10_REG(reg));
}

static void dcn10_write(void *mmio, uint32_t reg, uint32_t value)
{
	write32((uint8_t *)mmio + DCN10_REG(reg), value);
}

static void dcn10_update(void *mmio, uint32_t reg, uint32_t mask, uint32_t value)
{
	uint32_t old = dcn10_read(mmio, reg);

	dcn10_write(mmio, reg, (old & ~mask) | (value & mask));
}

void dcn10_disable_vga(void *mmio_base)
{
	uint32_t vga_mode;

	vga_mode = read32((uint8_t *)mmio_base + DCN10_REG1(D1VGA_CONTROL)) |
		read32((uint8_t *)mmio_base + DCN10_REG1(D2VGA_CONTROL)) |
		read32((uint8_t *)mmio_base + DCN10_REG1(D3VGA_CONTROL)) |
		read32((uint8_t *)mmio_base + DCN10_REG1(D4VGA_CONTROL));
	if (!(vga_mode & 1))
		return;

	write32((uint8_t *)mmio_base + DCN10_REG1(D1VGA_CONTROL), 0);
	write32((uint8_t *)mmio_base + DCN10_REG1(D2VGA_CONTROL), 0);
	write32((uint8_t *)mmio_base + DCN10_REG1(D3VGA_CONTROL), 0);
	write32((uint8_t *)mmio_base + DCN10_REG1(D4VGA_CONTROL), 0);

	/* Linux dcn10_disable_vga(): make DCHUBP latch extended-mode timing. */
	vga_mode = read32((uint8_t *)mmio_base + DCN10_REG1(VGA_TEST_CONTROL));
	write32((uint8_t *)mmio_base + DCN10_REG1(VGA_TEST_CONTROL),
		vga_mode | 0x101);
	printk(BIOS_INFO, "ATOMBIOS: DCN1 VGA disabled; DCHUBP render update started\n");
}

static int dcn10_power_on_domain(void *mmio, uint32_t config, uint32_t status)
{
	unsigned int i;

	/* Linux dcn10_enable_power_gating_plane() plus hubp/dpp_pg_control(). */
	dcn10_update(mmio, config, 0x101, 0x001);
	for (i = 0; i < 1000; i++) {
		if (!(dcn10_read(mmio, status) & 0xc0000000))
			return 0;
		udelay(1);
	}
	return -1;
}

static void dcn10_fill_test_pattern(void *address, uint32_t pitch,
				    uint16_t width, uint16_t height)
{
	static const uint32_t colors[] = {
		0xffff0000, 0xffffff00, 0xff00ff00,
		0xff00ffff, 0xff0000ff, 0xffff00ff,
	};
	uint16_t x, y;

	for (y = 0; y < height; y++) {
		uint32_t *row = (uint32_t *)((uint8_t *)address + y * pitch);

		for (x = 0; x < width; x++)
			row[x] = colors[(x * 6U) / width];
	}
}

static uint32_t div_round_up_u64(uint64_t value, uint32_t divisor)
{
	return (value + divisor - 1) / divisor;
}

static void dcn10_program_timing(void *mmio, const struct dcn10_timing *timing)
{
	uint32_t h_total = timing->h_active + timing->h_blank;
	uint32_t v_total = timing->v_active + timing->v_blank;
	uint32_t h_blank_start = h_total - timing->h_front_porch;
	uint32_t h_blank_end = h_blank_start - timing->h_active;
	uint32_t v_blank_start = v_total - timing->v_front_porch;
	uint32_t v_blank_end = v_blank_start - timing->v_active;
	uint32_t vstartup = timing->v_blank > 13 ? 13 : timing->v_blank - 1;
	uint32_t vupdate_offset = (h_total + 3) / 4;
	uint32_t vupdate_width;
	uint32_t vready_offset;
	uint32_t vready_dpp;
	uint32_t vready_dcf;
	uint32_t vcount_init = v_total - timing->v_front_porch;

	/* Linux DCN1 DML global-sync formulas; minimum deep-sleep DCFCLK is 8 MHz. */
	vupdate_width = div_round_up_u64(14ULL * timing->pixel_clock_khz, 8000) +
		div_round_up_u64(12ULL * timing->pixel_clock_khz,
				 timing->disp_clock_khz);
	vready_dpp = div_round_up_u64(150ULL * timing->pixel_clock_khz,
				      timing->disp_clock_khz);
	vready_dcf = div_round_up_u64(20ULL * timing->pixel_clock_khz, 8000) +
		div_round_up_u64(10ULL * timing->pixel_clock_khz,
				 timing->disp_clock_khz);
	vready_offset = vready_dpp > vready_dcf ? vready_dpp : vready_dcf;

	/* Linux optc1_program_timing() for a progressive RGB eDP stream. */
	dcn10_update(mmio, VTG_CONTROL, 0x80000000, 0);
	dcn10_update(mmio, OTG_DOUBLE_BUFFER_CONTROL, 0x00010100, 0x00000100);
	dcn10_write(mmio, OTG_H_TOTAL, h_total - 1);
	dcn10_write(mmio, OTG_H_SYNC_A, (uint32_t)timing->h_sync_width << 16);
	dcn10_write(mmio, OTG_H_BLANK_START_END,
		    h_blank_start | (h_blank_end << 16));
	dcn10_update(mmio, OTG_H_SYNC_A_CNTL, 1,
		     timing->hsync_positive ? 0 : 1);
	dcn10_write(mmio, OTG_H_TIMING_CNTL, 0);

	dcn10_write(mmio, OTG_V_TOTAL, v_total - 1);
	dcn10_write(mmio, OTG_V_TOTAL_MIN, v_total - 1);
	dcn10_write(mmio, OTG_V_TOTAL_MAX, v_total - 1);
	dcn10_write(mmio, OTG_V_SYNC_A, (uint32_t)timing->v_sync_width << 16);
	dcn10_write(mmio, OTG_V_BLANK_START_END,
		    v_blank_start | (v_blank_end << 16));
	dcn10_update(mmio, OTG_V_SYNC_A_CNTL, 1,
		     timing->vsync_positive ? 0 : 1);
	dcn10_write(mmio, OTG_INTERLACE_CONTROL, 0);

	dcn10_write(mmio, OTG_VSTARTUP_PARAM, vstartup);
	dcn10_write(mmio, OTG_VUPDATE_PARAM,
		    vupdate_offset | (vupdate_width << 16));
	dcn10_write(mmio, OTG_VREADY_PARAM, vready_offset);
	dcn10_update(mmio, OTG_CONTROL, 0x7000, 1U << 12);
	dcn10_update(mmio, VTG_CONTROL, 0x3fff8000, vcount_init << 15);
}

static void dcn10_program_dlg_ttu(void *mmio, const struct dcn10_timing *timing,
				  uint32_t pitch_pixels)
{
	uint32_t h_total = timing->h_active + timing->h_blank;
	uint32_t v_total = timing->v_active + timing->v_blank;
	uint32_t h_blank_end = h_total - timing->h_front_porch - timing->h_active;
	uint32_t v_blank_start = v_total - timing->v_front_porch;
	uint32_t v_blank_end = v_blank_start - timing->v_active;
	uint64_t ratio;
	uint32_t refcyc_per_htotal;
	uint32_t refcyc_h_blank_end;
	uint32_t pixel_delay;
	uint32_t refcyc_x_after_scaler;
	uint32_t line_delivery;
	uint32_t requests_per_line;
	uint32_t request_delivery;
	uint32_t qos_high;
	uint32_t min_ttu;

	/* Integer subset of Linux dml1_rq_dlg_get_dlg_params(), no VM or DCC. */
	ratio = ((uint64_t)timing->ref_clock_khz << 19) /
		timing->pixel_clock_khz;
	refcyc_per_htotal = (ratio * h_total * 256) >> 19;
	refcyc_h_blank_end = (ratio * h_blank_end) >> 19;
	pixel_delay = (132ULL * timing->pixel_clock_khz) /
		timing->disp_clock_khz;
	refcyc_x_after_scaler = (ratio * pixel_delay) >> 19;
	line_delivery = ((uint64_t)timing->ref_clock_khz * timing->h_active) /
		timing->pixel_clock_khz;
	requests_per_line = (pitch_pixels * 4 + 255) / 256;
	request_delivery = ((uint64_t)line_delivery << 10) / requests_per_line;
	qos_high = ((uint64_t)4 * h_total * timing->ref_clock_khz) /
		timing->pixel_clock_khz;
	min_ttu = 4 * timing->ref_clock_khz / 1000 +
		24 * timing->ref_clock_khz / timing->disp_clock_khz;

	dcn10_write(mmio, BLANK_OFFSET_0,
		    refcyc_h_blank_end | (v_blank_end << 16));
	dcn10_write(mmio, BLANK_OFFSET_1, v_blank_start * 4);
	dcn10_write(mmio, DST_DIMENSIONS, refcyc_per_htotal);
	dcn10_write(mmio, DST_AFTER_SCALER, refcyc_x_after_scaler);
	dcn10_write(mmio, REF_FREQ_TO_PIX_FREQ, ratio);
	dcn10_write(mmio, PREFETCH_SETTINS, (16U << 24) | (1U << 19));
	dcn10_write(mmio, VBLANK_PARAMETERS_0, 0);
	dcn10_write(mmio, PER_LINE_DELIVERY_PRE, line_delivery);
	dcn10_write(mmio, PER_LINE_DELIVERY, line_delivery);
	dcn10_write(mmio, DCN_TTU_QOS_WM, qos_high << 16);
	dcn10_write(mmio, DCN_SURF0_TTU_CNTL0,
		    request_delivery | (8U << 24));
	dcn10_write(mmio, DCN_SURF0_TTU_CNTL1, request_delivery);
	dcn10_write(mmio, DCN_GLOBAL_TTU_CNTL, min_ttu | (14U << 28));
}

int dcn10_program_scanout(void *mmio_base, uint64_t gpu_address,
			  void *cpu_address, size_t aperture_size,
			  const struct dcn10_timing *timing,
			  uint32_t *pitch_bytes)
{
	uint16_t width;
	uint16_t height;
	uint32_t pitch_pixels;
	uint32_t pitch;
	uint32_t dimensions;
	uint32_t hubp_cntl;

	if (!mmio_base || !cpu_address || !gpu_address || !timing ||
	    !timing->pixel_clock_khz || !timing->ref_clock_khz ||
	    !timing->disp_clock_khz || timing->v_blank < 2)
		return -1;
	width = timing->h_active;
	height = timing->v_active;
	pitch_pixels = (width + 63U) & ~63U;
	pitch = pitch_pixels * 4U;
	dimensions = ((uint32_t)height << 16) | width;
	if (aperture_size < (size_t)pitch * height)
		return -1;
	if (dcn10_power_on_domain(mmio_base, DOMAIN0_PG_CONFIG, DOMAIN0_PG_STATUS) ||
	    dcn10_power_on_domain(mmio_base, DOMAIN1_PG_CONFIG, DOMAIN1_PG_STATUS)) {
		printk(BIOS_ERR, "ATOMBIOS: DCN1 HUBP/DPP power-on failed\n");
		return -1;
	}

	/* Linux hubp1_set_blank(): stop requests while changing the plane. */
	hubp_cntl = dcn10_read(mmio_base, DCHUBP_CNTL);
	hubp_cntl &= ~HUBP_VTG_SEL_MASK;
	hubp_cntl |= HUBP_BLANK_EN | HUBP_TTU_DISABLE;
	dcn10_write(mmio_base, DCHUBP_CNTL, hubp_cntl);

	/* Linux hubp1_clk_cntl(), dpp1_dppclk_control(), opp_pipe_clock_control(). */
	dcn10_update(mmio_base, HUBP_CLK_CNTL, HUBP_CLOCK_ENABLE, HUBP_CLOCK_ENABLE);
	dcn10_update(mmio_base, DPP_CONTROL, DPP_CLOCK_ENABLE, DPP_CLOCK_ENABLE);
	dcn10_update(mmio_base, OPP_PIPE_CONTROL,
		     OPP_PIPE_CLOCK_ENABLE, OPP_PIPE_CLOCK_ENABLE);

	/* Linux dml1_extract_rq_regs() values for one linear 32-bpp RGB plane. */
	dcn10_write(mmio_base, DCN_EXPANSION_MODE, 0x56);
	dcn10_write(mmio_base, DCHUBP_REQ_SIZE_CONFIG, 0x055d1b70);
	dcn10_program_dlg_ttu(mmio_base, timing, pitch_pixels);

	/* Linear, non-DCC ARGB8888 surface, matching hubp1_program_surface_config(). */
	dcn10_update(mmio_base, DCSURF_SURFACE_CONTROL, 0x3f, 0);
	dcn10_write(mmio_base, DCSURF_TILING_CONFIG, 0);
	dcn10_update(mmio_base, DCSURF_SURFACE_CONFIG, 0x0000077f, 8);
	dcn10_write(mmio_base, DCSURF_SURFACE_PITCH, pitch_pixels - 1);
	dcn10_write(mmio_base, DCSURF_PRI_VIEWPORT_START, 0);
	dcn10_write(mmio_base, DCSURF_PRI_VIEWPORT_DIMENSION, dimensions);
	dcn10_update(mmio_base, DCSURF_FLIP_CONTROL, 0x2, 0);

	/* Linux hubp1_program_pixel_format() crossbar for ARGB. */
	dcn10_update(mmio_base, HUBPRET_CONTROL, 0x00f00fff, 0x00e00000);

	/* Linux dpp1_cnv_setup() and 1:1 dpp1_dscl_set_scaler_manual_scale(). */
	dcn10_write(mmio_base, CNVC_SURFACE_PIXEL_FORMAT, 8);
	dcn10_write(mmio_base, CNVC_FORMAT_CONTROL, 0x00000100);
	dcn10_write(mmio_base, DSCL_CONTROL, 0);
	dcn10_write(mmio_base, DSCL_RECOUT_START, 0);
	dcn10_write(mmio_base, DSCL_RECOUT_SIZE, dimensions);
	dcn10_write(mmio_base, DSCL_MPC_SIZE, dimensions);
	dcn10_update(mmio_base, DSCL_SCL_MODE, 0x7, 6);

	/* Linux mpc1_insert_plane(): DPP0 -> MPCC0 -> OPP0. */
	dcn10_update(mmio_base, MPCC_BOT_SEL, 0xf, 0xf);
	dcn10_update(mmio_base, MPCC_CONTROL, 0x3, 2);
	dcn10_update(mmio_base, MPCC_TOP_SEL, 0xf, 0);
	dcn10_update(mmio_base, MPCC_OPP_ID, 0xf, 0);
	dcn10_update(mmio_base, MPCC_UPDATE_LOCK_SEL, 0xf, 0);
	dcn10_update(mmio_base, MPC_OUT_MUX, 0xf, 0);

	/* Linux optc1_enable_optc_clock(), optc1_enable_crtc(), and unblank. */
	dcn10_program_timing(mmio_base, timing);
	dcn10_update(mmio_base, OPTC_INPUT_CLOCK_CONTROL, 0x3, 0x3);
	dcn10_update(mmio_base, OTG_CLOCK_CONTROL, 0x3, 0x3);
	mdelay(1);
	dcn10_update(mmio_base, OPTC_DATA_SOURCE_SELECT, 0x700, 0);
	dcn10_update(mmio_base, VTG_CONTROL, 0x80000000, 0x80000000);
	dcn10_update(mmio_base, OTG_CONTROL, 0x301, 0x301);
	dcn10_update(mmio_base, OTG_BLANK_CONTROL, 0x00010100, 0);
	printk(BIOS_INFO,
	       "ATOMBIOS: DCN1 OTG ctrl=0x%08x blank=0x%08x clock=0x%08x "
	       "input=0x%08x vtg=0x%08x htotal=0x%08x vtotal=0x%08x "
	       "vstartup=0x%08x vupdate=0x%08x vready=0x%08x\n",
	       dcn10_read(mmio_base, OTG_CONTROL),
	       dcn10_read(mmio_base, OTG_BLANK_CONTROL),
	       dcn10_read(mmio_base, OTG_CLOCK_CONTROL),
	       dcn10_read(mmio_base, OPTC_INPUT_CLOCK_CONTROL),
	       dcn10_read(mmio_base, VTG_CONTROL),
	       dcn10_read(mmio_base, OTG_H_TOTAL),
	       dcn10_read(mmio_base, OTG_V_TOTAL),
	       dcn10_read(mmio_base, OTG_VSTARTUP_PARAM),
	       dcn10_read(mmio_base, OTG_VUPDATE_PARAM),
	       dcn10_read(mmio_base, OTG_VREADY_PARAM));

	dcn10_fill_test_pattern(cpu_address, pitch, width, height);

	/* Linux hubp1_program_surface_flip_and_addr(): high first, low latches. */
	dcn10_write(mmio_base, DCSURF_PRIMARY_ADDRESS_HIGH, gpu_address >> 32);
	dcn10_write(mmio_base, DCSURF_PRIMARY_ADDRESS, gpu_address);

	/* Linux hubp1_set_blank(false). */
	hubp_cntl = dcn10_read(mmio_base, DCHUBP_CNTL);
	hubp_cntl &= ~(HUBP_BLANK_EN | HUBP_DISABLE |
		       HUBP_TTU_DISABLE | HUBP_VTG_SEL_MASK);
	dcn10_write(mmio_base, DCHUBP_CNTL, hubp_cntl);
	mdelay(20);
	printk(BIOS_INFO,
	       "ATOMBIOS: DCN1 HUBP cntl=0x%08x earliest=0x%08x%08x "
	       "address=0x%08x%08x pitch=0x%08x dlg=0x%08x/0x%08x/0x%08x\n",
	       dcn10_read(mmio_base, DCHUBP_CNTL),
	       dcn10_read(mmio_base, DCSURF_EARLIEST_INUSE_HIGH),
	       dcn10_read(mmio_base, DCSURF_EARLIEST_INUSE),
	       dcn10_read(mmio_base, DCSURF_PRIMARY_ADDRESS_HIGH),
	       dcn10_read(mmio_base, DCSURF_PRIMARY_ADDRESS),
	       dcn10_read(mmio_base, DCSURF_SURFACE_PITCH),
	       dcn10_read(mmio_base, BLANK_OFFSET_0),
	       dcn10_read(mmio_base, DST_DIMENSIONS),
	       dcn10_read(mmio_base, REF_FREQ_TO_PIX_FREQ));

	*pitch_bytes = pitch;
	printk(BIOS_INFO,
	       "ATOMBIOS: DCN1 scanout %ux%u pitch=%u GPU=0x%016llx CPU=%p\n",
	       width, height, pitch, (unsigned long long)gpu_address, cpu_address);
	return 0;
}

